from flask import Flask, request, jsonify
from sklearn.preprocessing import LabelEncoder
from sklearn.svm import SVC
from sklearn.metrics import accuracy_score
import face_recognition
import pickle
import os
import numpy as np

app = Flask(__name__)

class FaceRecognitionModel:
    def __init__(self, model_path='face_model.pkl', encodings_dir='encodings'):
        self.model_path = model_path
        self.encodings_dir = encodings_dir
        if os.path.exists(model_path):
            with open(model_path, 'rb') as file:
                self.svm_model = pickle.load(file)
            with open(f'{self.encodings_dir}/label_encoder.pkl', 'rb') as le_file:
                self.le = pickle.load(le_file)
        else:
            self.svm_model = None
            self.le = None

    def train(self, image_folder):
        encodings, labels = [], []
        for root, dirs, files in os.walk(image_folder):
            for file in files:
                if file.endswith(('jpg', 'jpeg', 'png')):
                    path = os.path.join(root, file)
                    image = face_recognition.load_image_file(path)
                    face_encodings = face_recognition.face_encodings(image)
                    if face_encodings:
                        encodings.append(face_encodings[0])
                        labels.append(os.path.basename(root))
        self.le = LabelEncoder().fit(labels)
        labels_num = self.le.transform(labels)
        self.svm_model = SVC(kernel='linear', probability=True)
        self.svm_model.fit(encodings, labels_num)

        with open(self.model_path, 'wb') as file:
            pickle.dump(self.svm_model, file)
        with open(f'{self.encodings_dir}/label_encoder.pkl', 'wb') as le_file:
            pickle.dump(self.le, le_file)

    def recognize(self, img_path):
        image = face_recognition.load_image_file(img_path)
        face_encodings = face_recognition.face_encodings(image)
        responses = []
        if face_encodings and self.svm_model:
            for encoding in face_encodings:
                probs = self.svm_model.predict_proba([encoding])[0]
                class_idx = np.argmax(probs)
                label = self.le.inverse_transform([class_idx])[0]
                responses.append({
                    "label": label,
                    "confidence": float(probs[class_idx]),
                    "probabilities": {self.le.inverse_transform([i])[0]: float(probs[i]) for i in range(len(probs))}
                })
        return responses

face_recognition_model = FaceRecognitionModel()

@app.route('/train', methods=['POST'])
def train_model():
    if 'images' in request.files:
        image_zip = request.files['images']
        image_folder = 'temp_photos'
        image_zip.save('uploaded_images.zip')
        os.system(f'unzip uploaded_images.zip -d {image_folder}')
        face_recognition_model.train(image_folder)
        return jsonify({"status": "success", "message": "Model trained with provided images"}), 200
    return jsonify({"status": "error", "message": "No images provided"}), 400

@app.route('/recognize', methods=['POST'])
def recognize_face():
    if 'image' not in request.files:
        return jsonify({"status": "error", "message": "No image file provided"}), 400
    image_file = request.files['image']
    image_path = 'temp_image.jpg'
    image_file.save(image_path)
    result = face_recognition_model.recognize(image_path)
    if not result:
        return jsonify({"status": "error", "message": "No faces found or recognition failure"}), 400
    return jsonify({"status": "success", "result": result}), 200

if __name__ == '__main__':
    app.run(debug=True)